sql:
SELECT AVG(engagement_rate) AS average_engagement_rate
FROM social_media
WHERE platform = 'Twitter';

SELECT c.company_name
FROM companies c
JOIN finance f ON c.company_id = f.company_id
WHERE f.market_capitalization = (
  SELECT MAX(market_capitalization) FROM finance
);

SELECT number_of_clients
FROM consulting
WHERE company_id = 1;

SELECT MAX(c.revenue) AS max_revenue
FROM companies c
JOIN fmcg f ON c.company_id = f.company_id;

SELECT company_name
FROM companies
ORDER BY company_name;

SELECT COUNT(*) AS news_count
FROM news_feeds
WHERE company_id = 1;

SELECT market_trends
FROM market_research
WHERE company_id = 1;
